package com.inventory.product.entity;
import java.math.BigDecimal;
import jakarta.persistence.*;
@Entity public class Product { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false,length=150) private String name; @Column(length=1000) private String description; @Column(nullable=false,precision=10,scale=2) private BigDecimal price; @Column(nullable=false) private Integer quantity; @Column(nullable=false,unique=true,length=50) private String sku; @Column(length=100) private String brand; @Column(length=255) private String imageUrl; @Column(length=20) private String status; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="category_id",nullable=false) private Category category;
 public Long getId(){return id;} public void setId(Long id){this.id=id;} public String getName(){return name;} public void setName(String name){this.name=name;} public String getDescription(){return description;} public void setDescription(String description){this.description=description;} public BigDecimal getPrice(){return price;} public void setPrice(BigDecimal price){this.price=price;} public Integer getQuantity(){return quantity;} public void setQuantity(Integer quantity){this.quantity=quantity;} public String getSku(){return sku;} public void setSku(String sku){this.sku=sku;} public String getBrand(){return brand;} public void setBrand(String brand){this.brand=brand;} public String getImageUrl(){return imageUrl;} public void setImageUrl(String imageUrl){this.imageUrl=imageUrl;} public String getStatus(){return status;} public void setStatus(String status){this.status=status;} public Category getCategory(){return category;} public void setCategory(Category category){this.category=category;} }
